+function parseListFlags(args: string[]): ListFlags {
+  const flags: ListFlags = {};
+  for (let i = 0; i < args.length; i++) {
+    const arg = args[i];
+    const next = args[i + 1];
+    switch (arg) {
+      case '--status':
+        if (!next) {
+          throw new Error('--status flag requires a value');
+        }
